components.css:
label {
  display: block;
  margin-bottom: var(--a-space-md);
  font-weight: var(--a-font-weight-medium);
}

input[type="email"],
input[type="text"] {
  width: 100%;
  padding: var(--a-space-md);
  background: var(--a-surface-overlay);
  color: var(--a-text-main);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  font-size: var(--a-text-base);
  transition: all var(--a-transition-base);
}

input[type="email"]:focus,
input[type="text"]:focus {
  outline: none;
  border-color: var(--a-primary);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--a-primary) 20%, transparent);
}

textarea {
  width: 100%;
  padding: var(--a-space-md);
  background: var(--a-surface-overlay);
  color: var(--a-text-main);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  font-size: var(--a-text-base);
  font-family: inherit;
  resize: vertical;
  transition: all var(--a-transition-base);
}

textarea:focus {
  outline: none;
  border-color: var(--a-primary);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--a-primary) 20%, transparent);
}

select {
  width: 100%;
  padding: var(--a-space-md);
  background: var(--a-surface-overlay);
  color: var(--a-text-main);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  font-size: var(--a-text-base);
  cursor: pointer;
  transition: all var(--a-transition-base);
}

select:focus {
  outline: none;
  border-color: var(--a-primary);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--a-primary) 20%, transparent);
}

label.checkbox {
  display: flex;
  align-items: center;
  gap: var(--a-space-md);
  cursor: pointer;
}

input[type="checkbox"] {
  width: 20px;
  height: 20px;
  cursor: pointer;
  accent-color: var(--a-primary);
}

input[type="checkbox"]:focus {
  outline: 2px solid var(--a-primary);
  outline-offset: 2px;
}

fieldset {
  border: none;
  padding: 0;
  margin: 0;
}

legend {
  font-weight: var(--a-font-weight-medium);
  margin-bottom: var(--a-space-md);
}

label.radio {
  display: flex;
  align-items: center;
  gap: var(--a-space-md);
  margin-bottom: var(--a-space-md);
  cursor: pointer;
}

input[type="radio"] {
  cursor: pointer;
  accent-color: var(--a-primary);
}

.input-group {
  display: flex;
  align-items: center;
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  overflow: hidden;
}

.input-group .prefix {
  padding: 0 var(--a-space-md);
  background: var(--a-surface-overlay);
  flex-shrink: 0;
}

.input-group input {
  flex: 1;
  border: none;
  padding: var(--a-space-md);
}

.input-group input:focus {
  outline: none;
  box-shadow: inset 0 0 0 2px var(--a-primary);
}

.form-group {
  margin-bottom: var(--a-space-lg);
}

.form-group label {
  display: block;
  margin-bottom: var(--a-space-sm);
  font-weight: var(--a-font-weight-medium);
}

.form-group input {
  width: 100%;
  padding: var(--a-space-md);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
}

.form-group span.error {
  display: block;
  margin-top: var(--a-space-xs);
  color: var(--a-error);
  font-size: var(--a-text-sm);
}

input[aria-invalid="false"] {
  border-color: var(--a-success);
  padding-right: calc(var(--a-space-lg) * 2);
  background-image: url('data:image/svg+xml;...');
  background-repeat: no-repeat;
  background-position: right var(--a-space-md) center;
}

input[aria-invalid="true"] {
  border-color: var(--a-error);
  color: var(--a-error);
}

.form-group .hint {
  margin-top: var(--a-space-xs);
  color: var(--a-text-muted);
  font-size: var(--a-text-sm);
}

form {
  display: flex;
  flex-direction: column;
  gap: var(--a-space-lg);
}

form button[type="submit"] {
  align-self: flex-start;
}
